Infraestrutura como codigo para storage - MediaStream Pro - multi-region-expansion:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "ap-sydney-1"
}

resource "oci_core_volume" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "storage-analytics-048"

  # configuração específica
  shape          = "BM.Standard.E5"

  tags = {
    project     = "MediaStream Pro - multi-region-expansion"
    environment = "analytics"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment analytics"
}

output "resource_id" {
  value = oci_core_volume.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "ap-sydney-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=<ocid>"
terraform apply -var="compartment_ocid=<ocid>" -auto-approve
```

**configuração:**
- Compartment: `analytics`
- Region: `ap-sydney-1`
- Shape: `BM.Standard.E5`
- OCPUs: `1`
- Storage: `50 GB`

documentação: https://registry.terraform.io/providers/oracle/oci/latest/docs
